local a=require"cc.expect"local b=bit32.band;local c={}local d={}do local e="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_"for f,g in e:gmatch("()(.)")do c[f-1]=g;d[g]=f-1 end end;local function h(i)a(1,i,"string")assert(#i==32,"invalid public key")i=i.."\0"local j=""for k in i:gmatch("...")do local l=(">I3"):unpack(k)local m=2^-18;for n=0,18,6 do j=j..c[b(l*m,63)]m=m*64 end end;return j:sub(1,43).."="end;local function o(p)if type(p)~="string"then return end;if#p~=44 then return end;if not p:match("^[A-Za-z0-9%-_]*=$")then return end;p=p:sub(1,43).."A"local q=""for k in p:gmatch("....")do local l=0;for f=1,4 do l=l*64+d[k:sub(f,f)]end;q=q..(">I3"):pack(l)end;return q:sub(1,32)end;return{encode=h,parse=o}
